// src/redux/store.ts
import { legacy_createStore as createStore, compose, Store } from "redux";
import { rootReducer, initialState } from "./reducers";
import { loadFromLocalStorage, saveToLocalStorage } from "@/lib/helper/storageLocal";

export type RootState = typeof initialState;
type StateKey = keyof RootState;

export const persistKeys: StateKey[] = ["notifications", "sidebar", "todo", "theme"];

const isBrowser = typeof window !== "undefined";
let persistTimeout: ReturnType<typeof setTimeout> | null = null;

/**
 * Helper to safely assign state values
 */
export function assignStateValue<K extends keyof RootState>(
  state: RootState,
  key: K,
  value: RootState[K]
) {
  state[key] = value;
}

/**
 * Load persisted slices (client only)
 */
const loadInitialState = (): RootState => {
  if (!isBrowser) return initialState;

  const loaded: RootState = { ...initialState };

  persistKeys.forEach((key) => {
    const saved = loadFromLocalStorage<RootState[typeof key]>(key);
    if (saved !== undefined) {
      assignStateValue(loaded, key, saved as RootState[typeof key]);
    }
  });

  return loaded;
};

/**
 * Persist updated slices
 */
const savePersistedState = (store: Store<RootState>) => {
  const state = store.getState();
  persistKeys.forEach((key) => saveToLocalStorage(state[key], key));
};

const schedulePersistedStateSave = (store: Store<RootState>) => {
  if (!isBrowser) return;

  if (persistTimeout) {
    clearTimeout(persistTimeout);
  }

  persistTimeout = setTimeout(() => {
    savePersistedState(store);
    persistTimeout = null;
  }, 120);
};

declare global {
  interface Window {
    __REDUX_DEVTOOLS_EXTENSION_COMPOSE__?: typeof compose;
  }
}

const composeEnhancers =
  (isBrowser && window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__) || compose;

let _store: Store<RootState> | undefined;

function getStoreSingleton(): Store<RootState> {
  if (_store) return _store;

  const preloadedState = loadInitialState();
  const store = createStore(rootReducer, preloadedState, composeEnhancers());
  if (isBrowser) store.subscribe(() => schedulePersistedStateSave(store));

  _store = store;
  return store;
}

export const store = getStoreSingleton();

import {
  createConnector,
  createDispatch,
  createStateSelector,
  createStateSelectorHook,
} from "react-redux-methods";

import {actions, selectors} from "./reducers";
import { store } from "./store";



export const reduxConnector = createConnector( selectors, actions );
export const dispatch = createDispatch( store.dispatch, actions );
export const getState= createStateSelector( store, selectors );
export const useGetState= createStateSelectorHook( selectors );

"use client";

import React, { useEffect, useState } from "react";
import { Provider } from "react-redux";
import { persistKeys, store } from "@/redux/store";
import { loadFromLocalStorage } from "@/lib/helper/storageLocal";
import type { RootState } from "@/redux/store";

// ✅ generic helper to assign values type-safely by key
function assignPersistedValue<K extends keyof RootState>(
  target: Partial<RootState>,
  key: K,
  value: RootState[K]
) {
  target[key] = value;
}

export default function StoreProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const persisted: Partial<RootState> = {};

    persistKeys.forEach((key) => {
      const value = loadFromLocalStorage<RootState[typeof key]>(key);
      if (value !== undefined) {
        // ✅ type-safe assignment with helper
        assignPersistedValue(persisted, key, value);
      }
    });

    // Dispatch a rehydration event to Redux store
    store.dispatch({
      type: "__REHYDRATE__",
      payload: persisted,
    });

    // Prevent hydration mismatch (Next.js SSR safety)
    requestAnimationFrame(() => setReady(true));
  }, []);

  if (!ready) {
    return <div suppressHydrationWarning />;
  }

  return <Provider store={store}>{children}</Provider>;
}

import { combineReducers } from "redux";

import {
  notificationsReducer,
  notificationsActions,
  notificationsSelectors,
  notifacationState,

} from "./notification";

import { SidebarActions, sidebarReducer, sidebarSelectors, sidebarState } from "./sidebar";
import { todoActions, todoReducer, todoSelectors, todoState } from "./todo";
import { themeReducer, themeActions, themeSelectors, themeState } from "./theme";

export const rootReducer = combineReducers({
  notifications: notificationsReducer, // <--- key should match 'selectionNode' value
  sidebar: sidebarReducer,
  todo: todoReducer,
  theme: themeReducer,
});

export const actions = {
  ...notificationsActions,
  ...SidebarActions,
  ...todoActions,
  ...themeActions,
};

export const selectors = {
  ...notificationsSelectors,
  ...sidebarSelectors,
  ...todoSelectors,
  ...themeSelectors,
};


export const initialState = {
  notifications: notifacationState, // <--- key should match 'selectionNode' value
  sidebar: sidebarState,
  todo: todoState,
  theme: themeState,
};

import { createReduxMethods, ComposePayload } from 'react-redux-methods';

export type INotification = {
  isOpen: boolean;
  message: string;
}

export const notifacationState: INotification = {
  isOpen: false,
  message: 'Hello',
};

const [notificationsReducer, notificationsActions, notificationsSelectors] = createReduxMethods({
  initialState: notifacationState,
  reducers: {
    setNotificationShow: (state, action) => ({
      ...state,
      isOpen: true,
      message: action.payload,
    }),
    setNotificationHide: () => notifacationState,
   
    updateNotification: (s, a: ComposePayload<string>) => ({
      ...s,
      message: a.payload,
    }),
  },
  selectionNode: 'notifications', 
  selectors: {
    getNotificationStatus: (s) => s.isOpen,
    getNotificationMessage: (s) => s.message || "", 
  },
});

// export all
export { notificationsReducer, notificationsActions, notificationsSelectors };

import { createReduxMethods } from "react-redux-methods";



export type SidebarStateProps = {
  isOpen: boolean;
};

export const sidebarState: SidebarStateProps = {
  isOpen: true,
};

const [sidebarReducer, SidebarActions, sidebarSelectors] = createReduxMethods({
  initialState: sidebarState,
  reducers: {
    setSidebarHide: (state) => ({
      ...state,
      isOpen: false,
    }),
    setSidebarShow: () => sidebarState,
  },
  selectionNode: "sidebar",
  selectors: {
    getSidebarStatus: (s) => s.isOpen,
  },
});

// export all
export { sidebarReducer, SidebarActions, sidebarSelectors };

import { createReduxMethods, ComposePayload } from "react-redux-methods";

/* ================== TYPES ================== */
export type ITodoItem = {
  id: string;
  text: string;
  completed: boolean;
};

export type ITodoState = {
  items: ITodoItem[];
};

/* ================== INITIAL STATE ================== */
export const todoState: ITodoState = {
  items: [],
};

/* ================== REDUX METHODS ================== */
const [todoReducer, todoActions, todoSelectors] = createReduxMethods({
  initialState: todoState,

  reducers: {
    addTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: [
        ...state.items,
        {
          id: crypto.randomUUID(),
          text: action.payload,
          completed: false, // ✅ default
        },
      ],
    }),

    toggleTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: state.items.map((t) =>
        t.id === action.payload
          ? { ...t, completed: !t.completed }
          : t
      ),
    }),

    deleteTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: state.items.filter((t) => t.id !== action.payload),
    }),

    clearTodos: () => todoState,
  },

  selectionNode: "todo",

  selectors: {
    getTodos: (s) => s.items,
    getTodoCount: (s) => s.items.length,
    getCompletedCount: (s) => s.items.filter((t) => t.completed).length,
  },
});

export { todoReducer, todoActions, todoSelectors };

export function loadFromLocalStorage<T>(
  key: string,
  validate?: (value: unknown) => value is T
): T | undefined {
  // Guard server-side usage where localStorage is unavailable.
  if (typeof window === "undefined" || typeof localStorage === "undefined") {
    return undefined;
  }

  let item: string | null;
  try {
    item = localStorage.getItem(key);
  } catch {
    return undefined;
  }

  if (!item) {
    return undefined;
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(item) as unknown;
  } catch {
    return undefined;
  }

  if (validate && !validate(parsed)) {
    return undefined;
  }

  return parsed as T;
}

export function saveToLocalStorage<T>(data: T, key: string): void {
  // Guard server-side usage where localStorage is unavailable.
  if (typeof window === "undefined" || typeof localStorage === "undefined") {
    return;
  }

  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (error) {
    console.error("Error saving to localStorage:", key, error);
  }
}

"use client";

import { useState } from "react";
import { reduxConnector } from "@/redux";
import type { ConnectedProps } from "react-redux";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Trash2 } from "lucide-react";

/* ================== CONNECTOR ================== */
const connector = reduxConnector(
  (s) => ({
    todos: s.getTodos,
    count: s.getTodoCount,
  }),
  (a) => ({
    addTodo: a.addTodo,
    toggleTodo: a.toggleTodo,
    deleteTodo: a.deleteTodo,
    clearTodos: a.clearTodos,
  })
);

type Props = ConnectedProps<typeof connector>;

function TodoPage({
  todos,
  count,
  addTodo,
  toggleTodo,
  deleteTodo,
  clearTodos,
}: Props) {
  const [value, setValue] = useState("");

  const handleAdd = () => {
    if (!value.trim()) return;
    addTodo(value.trim());
    setValue("");
  };

  return (
    <div className="flex items-center justify-center bg-muted p-6">
      <Card className="w-full max-w-md">
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            Todo App
            <Badge variant="secondary">{count}</Badge>
          </CardTitle>
        </CardHeader>

        <CardContent className="space-y-4">
          {/* Add Todo */}
          <div className="flex gap-2">
            <Input
              placeholder="Add a todo..."
              value={value}
              onChange={(e) => setValue(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleAdd()}
            />
            <Button onClick={handleAdd}>Add</Button>
          </div>

          {/* Todo List */}
          {todos.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center">
              No todos yet.
            </p>
          ) : (
            <ul className="space-y-2">
              {todos.map((todo) => (
                <li
                  key={todo.id}
                  className="flex items-center gap-3 rounded-md border p-2"
                >
                  <Checkbox
                    checked={todo.completed}
                    onCheckedChange={() => toggleTodo(todo.id)}
                  />

                  <span
                    className={[
                      "flex-1 text-sm transition",
                      todo.completed
                        ? "line-through text-muted-foreground"
                        : "",
                    ].join(" ")}
                  >
                    {todo.text}
                  </span>

                  <Button
                    size="icon"
                    variant="ghost"
                    onClick={() => deleteTodo(todo.id)}
                  >
                    <Trash2 className="h-4 w-4 text-destructive" />
                  </Button>
                </li>
              ))}
            </ul>
          )}

          {/* Clear */}
          {todos.length > 0 && (
            <Button
              variant="destructive"
              className="w-full"
              onClick={clearTodos}
            >
              Clear All
            </Button>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

export default connector(TodoPage);

"use client";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { reduxConnector } from "@/redux";
import type { ConnectedProps } from "react-redux";

const connector = reduxConnector(
  (s) => ({
    notificationStatus: s.getNotificationStatus,
    notificationMessage: s.getNotificationMessage,
  }),
  (a) => ({
    setNotificationShow: a.setNotificationShow,
    setNotificationHide: a.setNotificationHide,
  })
);

type Props = ConnectedProps<typeof connector>;

function NotificationPage({
  notificationStatus,
  notificationMessage,
  setNotificationShow,
  setNotificationHide,
}: Props) {
  return (
    <div className="flex items-center justify-center bg-muted p-6">
      <Card className="w-full max-w-md shadow-lg">
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            Notification System
            <Badge variant={notificationStatus ? "default" : "secondary"}>
              {notificationStatus ? "Visible" : "Hidden"}
            </Badge>
          </CardTitle>
        </CardHeader>

        <CardContent className="space-y-4">
          {notificationStatus ? (
            <Alert>
              <AlertTitle>Notification</AlertTitle>
              <AlertDescription>
                {notificationMessage}
              </AlertDescription>
            </Alert>
          ) : (
            <p className="text-sm text-muted-foreground">
              No active notification.
            </p>
          )}

          <div className="flex gap-3 justify-end">
            <Button
              onClick={() => setNotificationShow("Hello Adrian!")}
            >
              Show
            </Button>

            <Button
              variant="outline"
              onClick={() => setNotificationHide()}
            >
              Hide
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

export default connector(NotificationPage);
